const swiper=new Swiper(".swiper",{navigation:{prevEl:".btn__slider--prev",nextEl:".btn__slider--next"},pagination:{el:".slider__pag",clickable:!0},breakpoints:{1:{loop:!1,spaceBetween:20,slidesPerView:1,slidesPerGroup:1},768:{loop:!1,spaceBetween:40,slidesPerView:2,slidesPerGroup:2},1024:{loop:!0,spaceBetween:40,slidesPerView:3,slidesPerGroup:3}}}),header=document.querySelector(".header"),toggleClass="size--on-scroll";window.addEventListener("scroll",()=>{window.pageYOffset>50?header.classList.add(toggleClass):header.classList.remove(toggleClass)});const supAll=document.querySelectorAll(".tab__sup"),tabAll=document.querySelectorAll(".tab");supAll.forEach((e,t)=>{e.addEventListener("click",function(){const e=document.querySelectorAll(".tab__sup.sup--active"),l=supAll[t].classList.contains("sup--active");if(e.length>=1&&!l)for(let e=0;e<supAll.length;e++){const l=supAll[e].classList.contains("sup--active");e!==t&&l&&(supAll[e].classList.remove("sup--active"),tabAll[e].classList.remove("tab--show"))}l||(supAll[t].classList.add("sup--active"),tabAll[t].classList.add("tab--show"))})});const media=document.querySelector(".media"),video=document.querySelector(".video"),playButton=document.querySelector(".media__play__button");if(video&&playButton){function startVideo(){playButton.style.display="none",video.setAttribute("controls",""),video.play()}playButton.addEventListener("click",startVideo),video.addEventListener("ended",()=>{playButton.removeAttribute("style"),video.removeAttribute("controls")}),video.addEventListener("fullscreenchange",()=>{document.fullscreenElement?(media.style.borderRadius="initial",video.style.objectFit="contain"):(media.removeAttribute("style"),video.removeAttribute("style"))})}const ytVideo=document.querySelector(".yt-video");ytVideo&&ytVideo.addEventListener("fullscreenchange",()=>{document.fullscreenElement?media.style.borderRadius="initial":media.removeAttribute("style")});const accrSup=document.querySelectorAll(".accr__sup"),accrBtnAll=docu